import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const analyticContinuationPhilosopherArticles:Record<string,ArticleSection[]>={
  frege:[
    section('overview','The quiet beginning of analytic philosophy',[
      'Gottlob Frege is often treated as one of the starting points of analytic philosophy because he changed what philosophers could expect from logic, language, and mathematics. He was not a public school founder in the ordinary sense. He spent most of his career in Jena, wrote in a dense and technical style, and was only slowly recognized by the wider philosophical world. Yet his attempt to show that arithmetic rests on logic produced tools and distinctions that redirected twentieth-century philosophy.',
      'Frege matters because he made precision philosophically creative. He did not merely tidy up old arguments. He developed a new formal language, distinguished sense from reference, treated concepts as functions, and insisted that thoughts are objective contents rather than private mental episodes. Those moves shaped Russell, early Wittgenstein, Carnap, Quine, and much later philosophy of language. To read him well is to see analytic philosophy being born from a struggle over how thought can be both exact and shareable.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['frege','russell','wittgenstein'],['Begriffsschrift','The Foundations of Arithmetic','On Sense and Reference']),
    section('nineteenth-century-context','Arithmetic, rigor, and the crisis of foundations',[
      'Frege worked in a nineteenth-century environment transformed by new standards of mathematical rigor. Calculus, geometry, and number theory were being rebuilt with greater attention to proof, definition, and the status of basic concepts. Mathematicians and philosophers disagreed about whether numbers were mental constructions, abstractions from collections, formal symbols, or logical objects. Arithmetic looked obvious in schoolroom use, but its philosophical foundation was far from obvious.',
      'That setting explains why Frege saw arithmetic as a philosophical problem, not merely a technical domain. If numbers are psychological ideas, then arithmetic seems to vary with minds. If they are marks on paper, then mathematical truth becomes a matter of symbol manipulation. If they are empirical generalizations from collections, then the necessity of arithmetic becomes mysterious. Frege wanted an account that preserved objectivity, generality, and necessity without appealing to intuition in a vague or private way.'
    ],['logic','epistemology'],['frege'],['The Foundations of Arithmetic']),
    section('anti-psychologism','Logic against psychologism',[
      'Frege opposed psychologism, the view that logic is ultimately about mental processes, habits of thought, or laws of human psychology. He did not deny that people think psychologically. His point was that the validity of an inference is not the same as the causal history of someone making it. People can reason badly, feel certain about falsehoods, or fail to grasp a proof. Logic must judge such acts by standards that are not themselves just further psychological facts.',
      'This anti-psychologism is one of Frege\'s deepest contributions. It separates the content of thought from the private occurrence of thinking. The theorem remains what it is even if no one is attending to it; the inference is valid or invalid independently of how comfortable it feels. Later analytic philosophers inherited from Frege the idea that objectivity can be studied through language, logic, and public criteria of correctness rather than by inspecting inner mental images.'
    ],['logic','epistemology','philosophy-of-mind'],['frege'],['The Foundations of Arithmetic']),
    section('concept-script','The concept-script and the invention of modern logic',[
      'Frege\'s Begriffsschrift, published in 1879, introduced a formal system far more powerful than traditional syllogistic logic. Aristotle\'s logic handled important patterns involving subject and predicate, but it could not easily express multiple quantification, relations, or the structure of mathematical arguments. Frege\'s notation was visually unfamiliar and never became the standard printed form, yet the underlying ideas helped create modern predicate logic.',
      'The philosophical importance of this formal language lies in its ambition. Frege wanted to display the logical structure of thoughts with enough exactness to remove hidden gaps in proof. The system could represent claims such as every number having a successor or relations among objects that cannot be captured by simple term logic. Logic became not just a catalog of valid argument forms but a language for analyzing the structure of mathematical and philosophical content.'
    ],['logic','analytic-philosophy'],['frege','russell'],['Begriffsschrift']),
    section('logicism','Logicism and the definition of number',[
      'Frege\'s logicism holds that arithmetic can be derived from logic plus definitions. This was not the later formalist claim that mathematics is merely a game with symbols. Frege believed arithmetic has objective content, and he tried to explain that content by showing numbers to be logical objects. In The Foundations of Arithmetic, he criticizes views that make number depend on physical aggregates, subjective ideas, or arbitrary conventions.',
      'His famous strategy treats a statement of number as saying something about a concept. To say that there are three moons of a planet is not to attach a property to each moon separately, but to say that the concept moon of that planet is instantiated in a certain way. The full technical development in Basic Laws of Arithmetic proved vulnerable, but the basic shift remained powerful: number statements have logical form that ordinary grammar can conceal.'
    ],['logic','analytic-philosophy'],['frege','russell'],['The Foundations of Arithmetic','Basic Laws of Arithmetic']),
    section('context-principle','The context principle and meaning in sentences',[
      'One of Frege\'s most influential methodological rules is the context principle: words should be understood in the context of a proposition rather than in isolation. This rule helps him resist the idea that the meaning of a number word must be found by locating a private mental image or a physical object corresponding to it. The number two is not understood by staring at a pair of things; it is understood through its role in true and false judgments.',
      'The principle became central for later philosophy of language because it redirects questions about meaning from isolated names to the structure of sentences. It does not by itself solve every problem of meaning, and interpreters dispute exactly how broadly Frege intended it. Still, it marks a decisive turn. Philosophy should ask how expressions contribute to complete thoughts, what role they play in inference, and how public understanding is possible.'
    ],['philosophy-of-language','logic'],['frege','wittgenstein'],['The Foundations of Arithmetic']),
    section('sense-reference','Sense and reference',[
      'Frege\'s distinction between sense and reference addresses a puzzle about identity statements. If the morning star is the evening star, and both expressions refer to the planet Venus, why is the statement informative rather than trivial? Frege answers that the expressions have the same reference but present that reference through different senses, or modes of presentation. A name is not merely a tag attached to an object; it contributes a way in which the object is given in thought.',
      'This distinction opened a new era in the philosophy of language. It explains how co-referring terms can differ in cognitive value, why substitution can fail in reports of belief, and why understanding a sentence involves more than matching words to things. The distinction also generates difficulties. What exactly is a sense? How can senses be objective without becoming mysterious entities? Frege\'s answer is subtle and disputed, but the puzzle he posed has never gone away.'
    ],['philosophy-of-language','logic'],['frege','russell'],['On Sense and Reference']),
    section('concept-object','Function, concept, and object',[
      'Frege replaced the older subject-predicate model with a function-argument analysis. A concept is not a mental image or a class in the first instance, but something unsaturated that takes an object as argument and yields a truth-value. The expression is mortal can be treated as a function that maps Socrates to the True if Socrates falls under the concept. Relations can be handled by functions with more than one argument.',
      'This account lets logical analysis cut beneath misleading grammar. A sentence may look as if it names a thing called existence, or as if all predicates behave like names. Frege insists on differences of logical role. Objects are complete; concepts are predicative and incomplete in a distinctive sense. The view can sound strange, especially when Frege says that the concept horse is not a concept, but the strangeness arises from his attempt to keep logical categories from collapsing into ordinary grammar.'
    ],['logic','philosophy-of-language'],['frege'],['Function and Concept','On Concept and Object']),
    section('thought-truth','Thoughts, truth-values, and objectivity',[
      'Frege calls the sense of a declarative sentence a thought. A thought is not a private idea, a mental image, or a psychological event. It is the objective content that can be grasped by different thinkers, asserted, doubted, denied, or used in proof. This allows Frege to explain how people can disagree about the same proposition and how logic can evaluate shared content rather than private mental episodes.',
      'Frege also treats truth-values, the True and the False, as the references of sentences. That thesis is unusual, but it fits his system: just as a name refers to an object, a complete declarative sentence refers to a truth-value while expressing a thought. Many later philosophers rejected or reworked this detail, yet the wider point endured. Truth is not a feeling of certainty, and the contents of judgment are not owned by individual minds.'
    ],['logic','epistemology','philosophy-of-language'],['frege'],['The Thought','On Sense and Reference']),
    section('paradox-crisis','Russell\'s paradox and the broken system',[
      'Frege\'s technical project suffered a famous crisis when Bertrand Russell discovered a contradiction in the logical system of Basic Laws of Arithmetic. The problem concerned extensions of concepts and the possibility of considering the concept that applies to all concepts that do not apply to themselves. If such a concept applies to itself, it seems not to; if it does not, it seems to. Russell\'s letter reached Frege as the second volume of his work was being completed.',
      'The episode can be told too dramatically, as if Frege\'s entire philosophy collapsed in a single moment. The paradox did defeat a central axiom of the formal system, and Frege recognized the seriousness of the damage. But it did not erase his contributions to logic, meaning, anti-psychologism, or the analysis of number statements. It also stimulated later work by Russell, Whitehead, and others on type theory and the foundations of mathematics. The failure became part of analytic philosophy\'s inheritance.'
    ],['logic','analytic-philosophy'],['frege','russell'],['Basic Laws of Arithmetic','Principia Mathematica']),
    section('influence','Influence on Russell, Wittgenstein, and later analysis',[
      'Frege\'s influence was initially narrow but eventually immense. Russell recognized his importance after independently developing related concerns about mathematics and logic. Wittgenstein studied Frege closely and inherited from him the conviction that philosophical problems often arise from misunderstanding the logic of language. Carnap and other logical empiricists drew on Fregean logic even when they transformed it within new programs of syntax, semantics, and scientific language.',
      'Later philosophy of language repeatedly returns to Frege\'s questions. Theories of reference, descriptions, belief reports, compositional meaning, and propositional content often begin by accepting, revising, or attacking Fregean distinctions. Even philosophers who reject abstract senses may still work under the pressure of his examples. His legacy is not a doctrine everyone accepts, but a set of problems made sharper: how language hooks onto the world, how thought remains objective, and how logical form differs from surface grammar.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['frege','russell','wittgenstein','carnap'],['On Sense and Reference','Tractatus Logico-Philosophicus']),
    section('reading-strategy','How to read Frege without losing the thread',[
      'A good route begins with The Foundations of Arithmetic, because it shows Frege arguing in prose against tempting but inadequate accounts of number. Then read selections from Begriffsschrift to appreciate the formal breakthrough without being discouraged by the notation. After that, On Sense and Reference, Function and Concept, On Concept and Object, and The Thought show how his philosophy of language and logic grew from the same concerns.',
      'The most common misunderstanding is to treat Frege as a cold technician whose interest in language is merely symbolic. In fact, he is trying to protect the objectivity of thought from psychology, vague intuition, and misleading grammar. The difficulty is real: some of his entities and distinctions remain contested, and the failed logicist system cannot be ignored. Read him as a builder whose foundations cracked, but whose tools changed the discipline that inherited the ruins. The surface problem may be number, but the deeper lesson concerns public meaning, shared proof, and the standards that let thought be answerable to more than private conviction. That discipline is the heart of his legacy.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['frege','russell'],['The Foundations of Arithmetic','Begriffsschrift','On Sense and Reference','The Thought'])
  ],
  russell:[
    section('overview','Logic, analysis, and the public philosopher',[
      'Bertrand Russell stands at the point where analytic philosophy became both technically ambitious and publicly visible. He helped transform logic, attacked British idealism, defended logicism, wrote classic essays in philosophy of language and epistemology, and later became one of the most recognizable intellectuals of the twentieth century. His career is unusually long and uneven, moving from mathematical foundations to logical atomism, social criticism, education, pacifism, and popular writing.',
      'The center of Russell\'s philosophical importance is analysis. He believed that many philosophical confusions arise because grammar hides the true logical form of propositions. If language can be analyzed into clearer structures, questions about existence, knowledge, mathematics, and reality can be reformulated. Russell\'s answers changed across his career, but the analytic impulse remained: break the problem apart, locate its logical form, and do not trust ordinary expression simply because it sounds familiar.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['russell','frege','g-e-moore','wittgenstein'],['On Denoting','Principia Mathematica']),
    section('cambridge-revolt','The Cambridge revolt against idealism',[
      'Russell was educated in a Cambridge environment strongly marked by British idealism, especially the influence of F. H. Bradley and related forms of absolute idealism. These views often treated reality as an internally related whole and regarded ordinary distinctions among things as partial or abstract. Russell and G. E. Moore came to see this as obscuring the independence of facts, relations, and common judgments. Their rebellion helped create the style later called analytic philosophy.',
      'The revolt was not merely a change of slogans from idealism to realism. Russell\'s work on relations convinced him that relations cannot always be reduced to properties of individual terms or swallowed into a single whole. Mathematics itself seemed to require external relations, order, and plurality. The philosophical stakes were wide: if relations are real, then logic, mathematics, and the structure of facts can be studied without dissolving them into an all-embracing spiritual unity.'
    ],['analytic-philosophy','logic'],['russell','g-e-moore'],[]),
    section('logicism','Logicism and Principia Mathematica',[
      'Russell\'s logicism, developed partly in response to Frege and then with Alfred North Whitehead, aimed to show that mathematics could be derived from logical principles. The Principles of Mathematics set out the early program; Principia Mathematica attempted the monumental formal execution. This was not a small technical exercise. It sought to explain why mathematics has necessity and generality by locating its roots in logic rather than in intuition, empirical observation, or arbitrary formal manipulation.',
      'Principia is famous partly for its scale and difficulty, but its significance is broader than any one derivation. It helped establish formal logic as a central philosophical instrument. At the same time, the need for type theory and additional principles revealed how difficult the logicist project was. Later developments in mathematical logic changed the landscape again. Russell did not simply solve the foundations of mathematics, but he helped make foundational questions unavoidable for twentieth-century philosophy.'
    ],['logic','analytic-philosophy'],['russell','frege'],['The Principles of Mathematics','Principia Mathematica']),
    section('paradox-type-theory','Russell\'s paradox and type theory',[
      'Russell\'s paradox begins from a simple-looking question about collections: consider the class of all classes that are not members of themselves. Is that class a member of itself? If it is, then it should not be; if it is not, then it should be. The paradox exposed a contradiction in naive ways of treating classes and also damaged Frege\'s formal system. It showed that logical and set-theoretic abstraction could not proceed without restrictions.',
      'Russell\'s type theory was designed to prevent such self-reference by organizing expressions into levels. A class cannot be a member of itself because the relevant expression would cross type boundaries. The solution was ingenious but philosophically costly, especially when combined with the ramified theory of types and the axiom of reducibility. The lesson for analytic philosophy was lasting: formal clarity can reveal hidden disaster, but repairing the disaster may require principles whose own status needs philosophical defense.'
    ],['logic'],['russell','frege'],['Principia Mathematica']),
    section('descriptions','The theory of descriptions',[
      'Russell\'s essay On Denoting is one of the classic texts of analytic philosophy because it shows how logical analysis can dissolve puzzles about meaning and existence. Phrases such as the present king of France appear to refer to objects, even when no such object exists. Russell argues that definite descriptions are not genuine names. They are quantificational structures: a statement involving a description says that there is exactly one thing satisfying a condition and that it has a further property.',
      'The theory explains how a sentence can be meaningful without naming a mysterious nonexistent object. It also explains why sentences involving descriptions can be false rather than meaningless. The analysis influenced philosophy of language, logic, metaphysics, and later debates about reference. It also became a model of philosophical method: do not assume that grammatical form reveals logical form. A phrase that looks like a name may function very differently when analyzed.'
    ],['philosophy-of-language','logic'],['russell','frege'],['On Denoting']),
    section('acquaintance','Acquaintance, knowledge, and the limits of direct contact',[
      'Russell distinguished knowledge by acquaintance from knowledge by description. We are directly acquainted, in his view, with certain immediate data, universals, and perhaps ourselves, while much of what we know about ordinary objects and other people is mediated by descriptions. This distinction was meant to explain how thought can reach beyond immediate experience without becoming empty. A person can think about Bismarck, for example, through descriptions even without direct acquaintance with him.',
      'The theory belongs to Russell\'s attempt to combine empiricist discipline with logical analysis. He wanted to avoid both naive realism and idealist absorption of the world into mind. Yet the view creates pressures of its own. What exactly is given in acquaintance? Are sense-data private? How do descriptions connect with public objects? Later philosophers rejected many details, but Russell\'s distinction forced epistemology to ask how reference, evidence, and experience are related.'
    ],['epistemology','philosophy-of-mind','philosophy-of-language'],['russell'],['The Problems of Philosophy']),
    section('logical-atomism','Logical atomism and the structure of facts',[
      'Russell\'s logical atomism presents the world as composed of facts rather than things alone. A proposition is true or false depending on how it corresponds to facts, and complex propositions can be analyzed into simpler components. The view was developed in conversation with early Wittgenstein, though the two thinkers should not be collapsed into one position. Russell\'s version retains his concerns with acquaintance, relations, and the logical analysis of propositions.',
      'Logical atomism promised a disciplined metaphysics guided by logic. Instead of asking vaguely what reality is, the philosopher studies what kinds of facts must exist for meaningful propositions to be true or false. The program also faces difficulties. Are there truly atomic facts? Can language be fully analyzed into independent simples? Does the method assume too much about the fit between logic and world? These questions helped shape later debates about analysis, realism, and the limits of formal language.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['russell','wittgenstein'],['The Philosophy of Logical Atomism','Tractatus Logico-Philosophicus']),
    section('external-world','Science, perception, and the external world',[
      'Russell repeatedly returned to the problem of how knowledge of an external world is possible. He rejected simple certainty about ordinary objects, but he also resisted skepticism as a final destination. In works such as Our Knowledge of the External World and The Analysis of Matter, he tried to connect sense experience, logical construction, and scientific theory. Ordinary objects could be treated as logical constructions from actual and possible experiences, or later through structural relations described by science.',
      'This work shows Russell\'s philosophical temperament: he is skeptical of unexamined common sense, but he does not want philosophy to retreat from science into introspection. The problem is to explain how the public world described by physics relates to the immediate data of perception. His answers shifted, and some now look historically dated. Still, the guiding question remains alive in philosophy of mind and science: how do experience, structure, and theory combine to yield knowledge of a world beyond the momentary given?'
    ],['epistemology','philosophy-of-science','philosophy-of-mind'],['russell'],['Our Knowledge of the External World','The Analysis of Matter']),
    section('ethics-public-life','Ethics, value, and public responsibility',[
      'Russell is not remembered primarily as a technical moral philosopher in the way Moore is, but ethical and political concerns run through his life. He wrote about happiness, marriage, education, war, power, and social reform. His public commitments, including opposition to certain wars and nuclear weapons, made him a controversial public figure. These activities should not be confused with his formal logic, but they reveal a philosopher unwilling to separate clarity from responsibility.',
      'His ethical outlook changed over time and does not form one tidy system. He was suspicious of moral dogmatism, attracted to liberal and humanitarian ideals, and often critical of institutions that demanded obedience without reason. The interpretive challenge is to connect the public Russell with the technical Russell without pretending they are the same project. Logical analysis did not by itself dictate his politics, but the habits of independence, anti-obscurantism, and respect for evidence carried into his public voice.'
    ],['ethics','analytic-philosophy'],['russell','g-e-moore'],['The Conquest of Happiness']),
    section('relations','Frege, Moore, and Wittgenstein',[
      'Russell\'s relationship to Frege was one of discovery, admiration, and correction. He found in Frege a powerful predecessor in logicism and modern logic, even as Russell\'s paradox exposed a fatal flaw in Frege\'s formal system. With Moore, Russell shared the revolt against idealism and the insistence that philosophy should respect distinctions that idealist systems blurred. Moore\'s defense of common sense and Russell\'s logical analysis were different instruments in the same Cambridge reorientation.',
      'Wittgenstein was first Russell\'s student and then a severe critic. Russell recognized Wittgenstein\'s brilliance and helped bring the Tractatus to publication, but he did not simply become a Wittgensteinian. Their exchanges sharpened questions about logical form, facts, and the sayable. Russell\'s position in analytic history is therefore relational: he receives Frege, collaborates intellectually with Moore, provokes and is unsettled by Wittgenstein, and supplies later philosophers with both methods and targets.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['russell','frege','g-e-moore','wittgenstein'],['On Denoting','Tractatus Logico-Philosophicus']),
    section('tensions','Interpretive tensions and common misunderstandings',[
      'Russell is sometimes misread as if he held one stable doctrine called analytic philosophy from youth to old age. In fact, he changed his views about logic, perception, matter, language, and scientific knowledge. The consistency lies more in his methods and ambitions than in a fixed set of conclusions. He is also sometimes caricatured as a mere formalist, when many of his central questions concern reality, evidence, and the possibility of public knowledge. His revisions are part of the lesson: analysis is an activity of correction, not a monument to first drafts.',
      'Another misunderstanding treats his theory of descriptions as a universal magic key. It is a brilliant analysis of a class of expressions, not a proof that all philosophical problems vanish under quantifiers. Likewise, logical atomism should be read as an ambitious program with pressure points, not as the final metaphysics of analytic philosophy. Russell\'s greatness includes failure, revision, and overreach. He made philosophy sharper partly by making his own systems vulnerable to sharp criticism.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['russell'],['On Denoting','The Philosophy of Logical Atomism']),
    section('reading-strategy','How to read Russell',[
      'A beginner can start with The Problems of Philosophy, which gives a readable entry into perception, universals, and knowledge. Then read On Denoting to see analytic method at full intensity. Selected lectures from The Philosophy of Logical Atomism show how logic becomes metaphysics. After that, approach The Principles of Mathematics or guided selections from Principia Mathematica to understand the foundational ambition without expecting to master every formal detail at once.',
      'Read Russell historically and developmentally. Ask which problem he is solving at a given moment: idealism, paradox, reference, perception, scientific knowledge, or public error. Keep Moore and Frege nearby, and then read early Wittgenstein as both continuation and challenge. Russell rewards readers who enjoy bold construction and precise demolition. He is rarely the safest guide to a settled conclusion, but he is one of the best guides to why analytic philosophy became intellectually urgent. His changes of mind are evidence, not embarrassment.'
    ],['analytic-philosophy','logic','epistemology'],['russell','frege','g-e-moore','wittgenstein'],['The Problems of Philosophy','On Denoting','The Philosophy of Logical Atomism','Principia Mathematica'])
  ],
  'g-e-moore':[
    section('overview','Common sense with analytic force',[
      'G. E. Moore helped define early analytic philosophy by combining ordinary conviction with unusually careful argument. He is often remembered for holding up his hands to prove an external world or for asking whether good can be defined. Those memories can make him sound naive. In fact, Moore\'s work is powerful because he refuses to let impressive philosophical systems override what careful reflection still finds more certain than the arguments against it.',
      'Moore\'s philosophy is not simply an appeal to whatever people happen to believe. He asks which propositions we have better reason to trust than the premises used to deny them. This method shaped the Cambridge revolt against idealism, the development of analytic ethics, and later debates about skepticism and ordinary language. He made clarity, distinction, and plain speech philosophical virtues, but his plainness often conceals a subtle sense of where argument earns authority and where it only borrows prestige.'
    ],['analytic-philosophy','ethics','epistemology'],['g-e-moore','russell','wittgenstein'],['Principia Ethica','A Defence of Common Sense','Proof of an External World']),
    section('against-idealism','The revolt against British idealism',[
      'Moore\'s early work helped break the hold of British idealism at Cambridge. Idealist philosophers often argued that reality is not a collection of independent things but an internally related whole, and that ordinary distinctions between mind and world are abstractions from a deeper unity. Moore thought such views depended on confusions about relations, properties, and the act of awareness. His essay The Refutation of Idealism attacked the claim that being is inseparable from being perceived.',
      'The slogan associated with that essay, that consciousness and its object are distinct, became important for realism. Moore argued that the experience of yellow is not the same as yellow itself, and that recognizing an object does not make the object mental. The argument did not end idealism single-handedly, and later philosophers have disputed its details. But it gave Russell and others a model of direct, precise resistance to sweeping metaphysical systems.'
    ],['analytic-philosophy','epistemology','philosophy-of-mind'],['g-e-moore','russell'],['The Refutation of Idealism']),
    section('method','Moore\'s method of patient distinction',[
      'Moore\'s philosophical style can look pedestrian if one expects grand architecture. He often begins with a sentence that appears obvious, asks exactly what it means, separates several possible claims, and tests whether an argument has moved from one to another without notice. This patience was revolutionary in a context where broad metaphysical language could blur distinctions. Moore made it respectable to slow down and ask what, precisely, has been asserted.',
      'This method influenced analytic philosophy as much as any one doctrine. Moore showed that ordinary words can be philosophically useful, but only when handled carefully. He did not think every ordinary belief is immune to revision. Rather, he thought some claims are so deeply supported by experience and practice that a philosopher needs very strong reasons to reject them. When the reasons are weaker than the belief they attack, the reasonable response is to keep the belief and question the argument.'
    ],['analytic-philosophy','epistemology'],['g-e-moore','russell'],[]),
    section('principia-ethica','Principia Ethica and the autonomy of ethics',[
      'Moore\'s Principia Ethica made a decisive intervention in moral philosophy. He argued that good is a simple, indefinable, non-natural property. Attempts to define good in terms of pleasure, desire, evolution, social approval, or any other natural property commit what he called the naturalistic fallacy. Whether that label is perfectly chosen has been disputed, but the central challenge is clear: identifying what people desire or what produces pleasure does not by itself answer whether it is good.',
      'The book influenced the Bloomsbury circle, early analytic ethics, and later metaethics. Moore\'s non-naturalism is no longer accepted by everyone, and many philosophers reject his appeal to intuition. Still, his pressure on reduction remains important. Moral inquiry cannot simply be replaced by psychology, biology, sociology, or economics. Those fields may inform ethics, but Moore asks why their facts should settle the meaning or truth of value judgments. The question continues under many names in contemporary metaethics.'
    ],['ethics','analytic-philosophy'],['g-e-moore'],['Principia Ethica']),
    section('open-question','The open question argument',[
      'Moore\'s open question argument asks us to consider any proposed natural definition of good, such as good means pleasant. Even after understanding the definition, it still seems open to ask whether the pleasant really is good. The question is not like asking whether pleasant things are pleasant; it remains a substantive moral question. Moore concludes that good cannot be identical with any such natural property.',
      'The argument is subtle and controversial. Critics argue that some identities are informative, as water is H2O, so the fact that a question feels open may not show non-identity. Others think Moore confuses meaning with reference or relies too much on intuition. Even so, the argument forced moral philosophers to distinguish semantic, metaphysical, and epistemological questions. Are moral terms definable? What properties do they refer to? How do we know moral truths? Moore\'s simple question opened a complicated field.'
    ],['ethics','analytic-philosophy'],['g-e-moore'],['Principia Ethica']),
    section('organic-unities','Organic unities and the complexity of value',[
      'Moore is sometimes remembered as if he believed moral value could be counted by adding isolated units of goodness. In fact, Principia Ethica contains an important doctrine of organic unities. The value of a whole may not equal the sum of the values of its parts considered separately. A consciousness appreciating beauty, for example, might have a value that cannot be obtained by simply adding beauty and consciousness as independent items.',
      'This doctrine complicates Moore\'s ethics. It allows him to resist crude hedonism and simple aggregation. It also makes moral judgment more difficult, because the value of a situation may depend on relations among its elements. Later consequentialists and critics of consequentialism both found something to use here. Moore is not only the philosopher of one indefinable property; he is also a thinker of evaluative structure, asking how goods combine, intensify, or change when placed in wholes.'
    ],['ethics'],['g-e-moore'],['Principia Ethica']),
    section('common-sense','A Defence of Common Sense',[
      'In A Defence of Common Sense, Moore lists many propositions he says he knows with certainty: that he has a body, that the earth existed before his birth, that other people have had experiences, and so on. The point is not to celebrate unreflective opinion. Moore argues that he is more certain of these propositions than of any philosophical premise used to deny them. A skeptical or idealist argument therefore faces a burden it often fails to meet.',
      'This is a distinctive epistemological move. Moore does not refute skepticism by explaining the deep structure of knowledge. He says, in effect, that some ordinary claims are better known than the abstract principles that imply we do not know them. Critics reply that this begs the question against the skeptic, because the skeptic asks how such knowledge is possible. Moore\'s answer may not satisfy that demand, but it shifts attention to comparative certainty and the cost of philosophical denial.'
    ],['epistemology','analytic-philosophy'],['g-e-moore'],['A Defence of Common Sense']),
    section('external-world','Proof of an external world',[
      'Moore\'s Proof of an External World famously argues by raising one hand, then another, and saying that here is one hand and here is another. If hands exist, external things exist; therefore an external world exists. The argument is often mocked because it seems too simple for such a large problem. Moore\'s real point concerns standards of proof. He claims he can know the premises even if he cannot satisfy every philosophical demand for explaining how he knows them.',
      'The proof divides readers. Some see it as a decisive reminder that skeptical standards are unreasonable; others see it as failing to engage the skeptical challenge. Its influence on later philosophy is enormous precisely because of this tension. Wittgenstein\'s On Certainty, for example, takes Moorean propositions as starting points for examining the background conditions of doubt and knowledge. Moore\'s hands continue to matter because they force epistemology to ask what kind of answer skepticism is entitled to demand.'
    ],['epistemology','analytic-philosophy'],['g-e-moore','wittgenstein'],['Proof of an External World','On Certainty']),
    section('russell-wittgenstein','Moore, Russell, and Wittgenstein',[
      'Moore and Russell were allies in the rejection of idealism, but their temperaments differed. Russell moved toward formal logic, ambitious systems, and broad reconstruction. Moore moved by careful discrimination of claims and by defense of propositions that seemed more certain than their denials. Their differences helped give early analytic philosophy its double character: technical logical analysis on one side, ordinary clarity and common-sense realism on the other.',
      'Wittgenstein admired Moore\'s honesty and seriousness, even while transforming the questions Moore raised. Moore\'s notes helped preserve some of Wittgenstein\'s lectures, and Moorean certainty became a central theme in Wittgenstein\'s late work. The relation is not one of simple influence from master to disciple. Moore\'s plain claims about hands, bodies, and other minds became material for a deeper investigation into the grammar of knowing, doubting, and being certain.'
    ],['analytic-philosophy','epistemology'],['g-e-moore','russell','wittgenstein'],['On Certainty']),
    section('ethics-influence','Ethical influence and later metaethics',[
      'Moore\'s ethical influence is both direct and indirect. Directly, Principia Ethica shaped early twentieth-century discussions of intrinsic value, intuition, and the indefinability of good. Indirectly, it helped create metaethics as a distinct area: philosophers began asking about the meaning of moral terms, the status of moral properties, and the relation between moral judgment and natural fact. Even opponents of Moore often work in a field he helped define.',
      'Later noncognitivists, naturalists, error theorists, and moral realists all respond in different ways to Moorean pressure. Some reject non-natural properties but preserve the thought that moral language has a special function. Others defend moral realism while giving up Moore\'s simple intuitionism. The historical importance is not that Moore settled moral philosophy. It is that he made reduction difficult. Anyone who says that good is just pleasure, desire, fitness, or approval now owes a more careful account.'
    ],['ethics','analytic-philosophy'],['g-e-moore'],['Principia Ethica']),
    section('misunderstandings','Common misunderstandings and limits',[
      'Moore is easy to underestimate. His prose is plain, his examples ordinary, and his conclusions sometimes look like common sense dressed as philosophy. But the plainness is strategic. He often asks whether a sophisticated argument has become less credible than the ordinary proposition it denies. That question can be philosophically devastating. At the same time, Moore\'s method has limits. It may defend starting points without explaining their deeper status.',
      'His ethics faces related difficulties. The appeal to intuition can seem epistemically mysterious, and the indefinability of good does not by itself explain how moral disagreement should be resolved. His epistemology can seem to answer skepticism from outside rather than meeting it on its own terms. These are real objections. Moore\'s importance lies in forcing philosophers to justify the move from abstract argument to revisionary conclusion, not in exempting common sense from all criticism. That pressure remains useful even where his answers fail.'
    ],['analytic-philosophy','ethics','epistemology'],['g-e-moore'],['Principia Ethica','A Defence of Common Sense']),
    section('reading-strategy','How to read Moore',[
      'Begin with The Refutation of Idealism to see the early break with idealism, then read the first chapters of Principia Ethica for the open question argument and the attack on naturalistic definitions. After that, A Defence of Common Sense and Proof of an External World show Moore\'s epistemological method at its most memorable. Reading these works beside Russell clarifies how different early analytic styles could share a common revolt.',
      'The best reading strategy is to take Moore\'s simplicity seriously without becoming impatient with it. Ask what he thinks is more certain than what, and why. Notice when he is making a semantic point, an epistemic point, or a metaphysical point. Then read Wittgenstein\'s On Certainty as a later transformation of Moorean themes. Moore\'s work is not flashy, but it trains a durable philosophical instinct: never let a grand conclusion pass until its premises have earned the right to be believed. That instinct explains why an apparently modest philosopher could reshape a whole style of argument.'
    ],['analytic-philosophy','ethics','epistemology'],['g-e-moore','russell','wittgenstein'],['The Refutation of Idealism','Principia Ethica','A Defence of Common Sense','Proof of an External World','On Certainty'])
  ],
  carnap:[
    section('overview','The architect of logical empiricism',[
      'Rudolf Carnap was one of the central figures of logical empiricism and one of the most constructive philosophers of the twentieth century. He wanted philosophy to abandon speculative metaphysics and become a disciplined clarification of language, logic, and scientific concepts. Unlike philosophers who use criticism mainly to destroy, Carnap built systems: formal languages, criteria of meaningfulness, accounts of probability, models of explanation, and frameworks for scientific discourse.',
      'Carnap\'s reputation has changed repeatedly. He was once treated as a symbol of an overly strict verificationism that later philosophy surpassed. More recent readers often find a subtler thinker: tolerant about linguistic frameworks, deeply engaged with science, and aware that philosophical disputes can arise from mixing rules of language with questions inside a language. His project is best understood as an attempt to make intellectual cooperation possible by clarifying what kind of question is being asked.'
    ],['analytic-philosophy','logic','philosophy-of-science'],['carnap','quine','russell'],['The Logical Structure of the World','The Logical Syntax of Language']),
    section('vienna-circle','Vienna Circle context and intellectual ambition',[
      'Carnap belonged to the Vienna Circle, a group of philosophers, scientists, and mathematicians who sought a scientific world-conception in the aftermath of dramatic changes in logic, physics, and European politics. They admired Frege, Russell, Einstein, and the new mathematical logic. They rejected obscurantist metaphysics and hoped that logical analysis could clarify the language of science. The movement was diverse, and Carnap should not be reduced to its most simplified slogans.',
      'The context matters because logical empiricism was not only a technical doctrine. It was also an intellectual culture committed to public reason, anti-authoritarian inquiry, and the unity of scientific knowledge. Carnap\'s later work in Prague and the United States continued this ambition under changing conditions. The political catastrophe of Europe in the 1930s disrupted the Circle, but it did not erase the project. Carnap carried its constructive side into debates about language, confirmation, probability, and semantics.'
    ],['analytic-philosophy','philosophy-of-science','logic'],['carnap'],[]),
    section('aufbau','The Aufbau and rational reconstruction',[
      'In The Logical Structure of the World, often called the Aufbau, Carnap tried to reconstruct scientific concepts from a minimal basis using logical methods. The project is sometimes described as phenomenalist because it begins from elementary experiences, but Carnap\'s aim was not simply to say that physical objects are private sensations. He wanted to show how concepts could be ordered in a system of definitions or constructions that makes their logical relations explicit.',
      'The Aufbau reflects both ambition and fragility. Its technical details did not become a permanent foundation for science, and Carnap later revised many assumptions. Yet the method of rational reconstruction remained important. Philosophy need not reproduce messy historical discovery; it can build clarified models that display how concepts function. Even when the model is idealized, it can reveal dependencies, ambiguities, and alternatives that ordinary scientific language leaves implicit.'
    ],['epistemology','logic','philosophy-of-science'],['carnap','russell'],['The Logical Structure of the World']),
    section('metaphysics-critique','The critique of metaphysics',[
      'Carnap\'s critique of metaphysics is most famous in essays that treat some traditional philosophical sentences as lacking cognitive meaning. His target was not poetry, emotion, or existential seriousness as such. He objected to sentences that appear to make factual claims while violating the logical and empirical conditions that would give them a role in inquiry. Metaphysical language, on this view, can mimic assertion without contributing testable or logically structured content.',
      'This critique is easy to caricature as philistinism. Carnap was not saying that only laboratory reports matter or that art and ethical commitment are worthless. He was asking whether certain philosophical utterances have the kind of meaning they pretend to have. The difficulty lies in formulating a criterion of meaning that is neither too narrow nor self-defeating. Later philosophers criticized verificationism, but Carnap\'s suspicion of pseudo-questions remains a powerful analytic discipline.'
    ],['analytic-philosophy','philosophy-of-language','philosophy-of-science'],['carnap'],['The Elimination of Metaphysics Through Logical Analysis of Language']),
    section('syntax','Logical syntax and philosophy as language analysis',[
      'In The Logical Syntax of Language, Carnap proposed that many philosophical problems should be treated as questions about the formal rules of linguistic systems. Instead of asking, in a metaphysical tone, what numbers really are, one can specify a language in which numerical expressions have defined roles. Philosophy becomes the logical syntax of scientific language: the study of formation rules, transformation rules, and the consequences of adopting a framework.',
      'This syntactic phase shows Carnap at his most programmatic. He wanted to replace disputes about ultimate reality with explicit choices about linguistic rules. The approach was powerful because it made alternatives visible. It also drew criticism because syntax alone seemed unable to handle meaning, reference, and interpretation. Carnap later moved toward semantics, but the syntactic period established a theme that remained central: philosophical clarity often comes from making the rules of discourse explicit.'
    ],['logic','philosophy-of-language','analytic-philosophy'],['carnap','quine'],['The Logical Syntax of Language']),
    section('tolerance','The principle of tolerance',[
      'Carnap\'s principle of tolerance says that there is no single correct logic or language forced on us independently of our purposes. We may construct linguistic frameworks with different rules, provided we state them clearly. Questions about which framework to adopt are practical, conventional, and goal-relative rather than metaphysical discoveries about the one true language of reality. This tolerance is one of Carnap\'s most important and often misunderstood ideas.',
      'Tolerance does not mean that anything goes. A framework can be more or less useful, fruitful, simple, expressive, or connected to scientific practice. Once a framework is adopted, internal questions can have determinate answers. Carnap\'s point is that disputes about adopting the framework should not masquerade as factual disputes inside it. This distinction between internal and external questions later became central to his defense of abstract entities and to his disagreement with Quine.'
    ],['logic','philosophy-of-language','philosophy-of-science'],['carnap','quine'],['The Logical Syntax of Language','Empiricism, Semantics, and Ontology']),
    section('semantics','Semantics, modality, and abstract entities',[
      'Carnap\'s later work moved from syntax to semantics. Meaning and Necessity developed formal tools for intension, extension, and modal notions. He also argued that accepting a linguistic framework containing numbers, propositions, or other abstract entities does not require a heavy metaphysical discovery. Within the framework, one can answer internal questions about numbers or classes. The external question of whether to adopt the framework is practical.',
      'This position shaped later debates about ontology. Carnap tried to deflate metaphysical anxiety by treating frameworks as instruments. If mathematical language is indispensable and well-governed, there is no further deep question of whether numbers exist in a metaphysical sense. Quine objected that this distinction between internal and external questions depends on an analytic-synthetic boundary he rejected. The disagreement became one of the defining disputes in mid-century analytic philosophy.'
    ],['philosophy-of-language','logic','analytic-philosophy'],['carnap','quine'],['Meaning and Necessity','Empiricism, Semantics, and Ontology']),
    section('confirmation','Confirmation, probability, and inductive logic',[
      'Carnap devoted major effort to confirmation theory and inductive logic. Deductive logic explains validity, but science also relies on evidence that supports hypotheses without entailing them. Carnap sought formal measures of confirmation and logical probability that could clarify how evidence bears on general claims. This work belongs to the logical empiricist hope that scientific reasoning can be made more explicit and rationally assessable.',
      'The project faced serious challenges. Inductive support depends on background language, choice of predicates, prior assumptions, and the structure of hypotheses. Later work by Hempel, Goodman, Bayesian theorists, and others complicated the picture. Carnap\'s specific systems did not become the final logic of science, but his questions remain central. What is confirmation? How does evidence support theory? Can probability be logical, subjective, or both? Carnap made these questions precise enough for productive disagreement.'
    ],['philosophy-of-science','logic','epistemology'],['carnap'],['Logical Foundations of Probability','Testability and Meaning']),
    section('science-unity','Philosophy of science and the unity of knowledge',[
      'Carnap\'s philosophy of science aimed to clarify the language in which scientific claims are stated, connected, and tested. He was interested in reduction sentences, theoretical terms, observation language, probability, and the relation among different scientific vocabularies. The ideal of unified science did not mean that all disciplines should be crudely reduced to physics overnight. It meant that scientific claims should be connected through shared logical and empirical standards.',
      'This project was optimistic but not simple. Scientific theories contain terms that are not directly observable, and their meaning depends on networks of laws, measurement procedures, and inferential roles. Carnap\'s attempts to handle theoretical language show him revising earlier strict empiricist assumptions. He remained committed to clarity and empiricism, but he increasingly recognized the complexity of scientific meaning. That development makes him more flexible than the textbook image of logical positivism often suggests.'
    ],['philosophy-of-science','logic','epistemology'],['carnap','quine'],['Testability and Meaning']),
    section('temperament','Constructive temperament and anti-dogmatism',[
      'Carnap\'s public image can make him seem like a philosopher of prohibition, but his strongest instinct was constructive. He liked to build formal tools, compare alternative languages, and ask what intellectual purpose a vocabulary serves. That temperament explains why he could be both severe toward metaphysical pseudo-claims and unusually liberal about adopting different logics or frameworks. The enemy was not plurality; it was unclarity about rules and standards.',
      'This constructive side also gives Carnap\'s work an ethical and political tone, though usually an indirect one. Clear public language, cooperative inquiry, and resistance to obscurantist authority mattered to the scientific world-conception he defended. He did not think formal logic would by itself solve social conflict. But he did think intellectual life improves when disagreements are made explicit enough for participants to see whether they are testing facts, choosing conventions, or expressing attitudes.'
    ],['analytic-philosophy','logic','philosophy-of-science'],['carnap'],[]),
    section('quine-dispute','Carnap and Quine',[
      'Carnap\'s disagreement with Quine is a central episode in analytic philosophy. Carnap distinguished analytic truths, fixed by linguistic rules, from synthetic truths, answerable to experience. Quine challenged this distinction in Two Dogmas of Empiricism, arguing that no clear boundary separates truths by meaning from truths by fact. He also rejected reductionism, the idea that each meaningful statement can be tied to its own confirming experiences.',
      'The dispute is often presented as Quine defeating Carnap, but that is too simple. Carnap can be read as offering a pragmatic account of frameworks rather than a metaphysical boundary carved into reality. Quine presses the point that even logic and language are embedded in the total web of belief. Their disagreement concerns the status of linguistic rules, the nature of ontology, and the relation between philosophy and science. Both sides remain philosophically alive.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['carnap','quine'],['Two Dogmas of Empiricism','Empiricism, Semantics, and Ontology']),
    section('misunderstandings','Misreadings and interpretive tensions',[
      'Carnap is often reduced to a crude verificationist who thought every meaningful sentence must be directly observable. That picture misses his development, his tolerance about formal languages, and his later semantic work. He did seek criteria that would exclude pseudo-statements, and some formulations were too strict. But his broader project was constructive clarification, not anti-humanistic policing of every meaningful activity.',
      'Another misunderstanding treats Carnap as indifferent to ontology because he was afraid of metaphysics. A better reading sees him as relocating ontological commitment inside linguistic frameworks and practical choices. The tension is whether this relocation really dissolves metaphysics or simply redescribes it. Carnap\'s work remains important because it asks philosophers to separate internal questions from framework choice, and to state clearly what would count as progress in a dispute.'
    ],['analytic-philosophy','philosophy-of-science','philosophy-of-language'],['carnap','quine'],['Empiricism, Semantics, and Ontology']),
    section('reading-strategy','How to read Carnap',[
      'Begin with accessible essays on metaphysics, protocol sentences, and empiricism before approaching the larger books. The Logical Structure of the World shows the early constructive ambition; The Logical Syntax of Language displays the syntactic program and tolerance; Meaning and Necessity and Empiricism, Semantics, and Ontology show the later semantic and ontological framework. Reading him beside Neurath, Schlick, Russell, and Quine helps prevent a one-person caricature of logical empiricism.',
      'The best question to bring to Carnap is not whether he finally found the perfect scientific language. He did not. Ask instead how explicit language construction changes philosophical disagreement. Which questions become internal to a framework? Which are practical choices about adopting rules? Which are confused by grammar? Carnap\'s enduring value lies in his disciplined optimism: the belief that many intellectual conflicts become less mysterious when we build clearer languages for having them.'
    ],['analytic-philosophy','philosophy-of-science','logic'],['carnap','quine','russell'],['The Logical Structure of the World','The Logical Syntax of Language','Meaning and Necessity','Empiricism, Semantics, and Ontology'])
  ],
  quine:[
    section('overview','The naturalist who unsettled analytic philosophy',[
      'W. V. O. Quine transformed analytic philosophy by challenging distinctions that had organized logical empiricism and early analysis. He rejected a sharp boundary between analytic and synthetic truths, treated our beliefs as a connected web answerable to experience as a whole, and argued that philosophy is continuous with empirical science. His work is technical, terse, and often dryly witty, but its effect was dramatic: it made the inherited picture of meanings, definitions, and foundations look unstable.',
      'Quine did not abandon logic or clarity. He was a master of formal regimentation and an exacting philosopher of language. What he resisted was the idea that philosophy occupies a separate a priori standpoint from which it can certify science, meaning, or ontology. Instead, inquiry begins from within our best evolving theory of the world. We improve that theory using logic, evidence, simplicity, and scientific practice, but there is no external tribunal called pure meaning that stands above it.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['quine','carnap','russell'],['Two Dogmas of Empiricism','Word and Object']),
    section('background','From logical empiricism to naturalism',[
      'Quine was deeply formed by the very tradition he later criticized. He studied mathematical logic, encountered Carnap and the logical empiricists, and shared their respect for science, formal clarity, and suspicion of inflated metaphysics. His criticism therefore came from inside the analytic and empiricist project, not from a romantic rejection of it. He accepted much of the scientific temperament while questioning the linguistic doctrines that logical empiricism used to protect empiricism.',
      'This background matters because Quine\'s naturalism is not a retreat into common sense or a celebration of vague holism. It is a disciplined proposal about where philosophy belongs. Philosophy does not justify science from outside; it studies knowledge, language, and ontology using the resources of science itself. That move changes epistemology, metaphysics, and philosophy of language. It also raises a worry: if philosophy is inside science, can it still critically assess science\'s deepest assumptions?'
    ],['analytic-philosophy','philosophy-of-science','epistemology'],['quine','carnap'],[]),
    section('two-dogmas','Two Dogmas and the attack on analyticity',[
      'Two Dogmas of Empiricism attacks two linked ideas: that there is a principled distinction between analytic truths true by meaning and synthetic truths true by fact, and that each meaningful statement can be reduced to some range of confirming experiences. Quine argues that attempts to define analyticity appeal to synonymy, meaning, or rules in ways that circle back on the same unexplained notions. The boundary logical empiricists needed begins to look less clear than advertised.',
      'The essay\'s positive image is holistic. Statements face experience not one by one but as part of a corporate body of theory. When experience conflicts with expectation, many revisions are possible: adjust an observation claim, an auxiliary hypothesis, a theoretical assumption, or even logic in extreme cases. This does not make all beliefs equally revisable in practice. Some are central and costly to change. But no belief is protected by meaning alone in a way that makes it immune to revision.'
    ],['analytic-philosophy','epistemology','philosophy-of-language'],['quine','carnap'],['Two Dogmas of Empiricism']),
    section('web-belief','The web of belief',[
      'Quine\'s metaphor of the web of belief is one of the most influential images in twentieth-century epistemology. Our beliefs form an interconnected network. Peripheral beliefs are more directly exposed to sensory stimulation; central beliefs, such as logic and mathematics, are connected more deeply to the system and are therefore harder to revise. Experience prompts adjustments, but the choice of adjustment depends on simplicity, conservatism, explanatory power, and the overall balance of theory.',
      'The web image should not be mistaken for subjectivism. Quine does not say we may believe whatever we like. Experience constrains inquiry, and science is our best organized response to that constraint. The point is that evidence never dictates a unique revision in isolation. This holism influenced philosophy of science, confirmation theory, and debates about rationality. It also made foundationalist dreams harder to sustain, because no statement serves as an absolutely unrevisable foundation outside the network.'
    ],['epistemology','philosophy-of-science'],['quine'],['From a Logical Point of View','Two Dogmas of Empiricism']),
    section('ontology','Ontological commitment and regimentation',[
      'Quine\'s approach to ontology is captured by his test of what a theory must quantify over. To ask what exists, we look to our best regimented theory and see what entities must be values of bound variables for the theory to be true. This does not settle ontology by ordinary grammar. A sentence may appear to mention something without our best logical paraphrase committing us to it. Regimentation reveals the commitments of a theory in clear logical form.',
      'This method connects metaphysics to science and logic. Quine is not asking what entities sound familiar or intuitively respectable; he asks what our best theory requires. He was willing to accept abstract objects such as sets because mathematics is deeply embedded in science, while remaining suspicious of meanings, propositions, and intensional entities. Critics argue that his criterion is too tied to first-order logic or too austere about modality and meaning. Even so, it made ontology newly precise.'
    ],['logic','analytic-philosophy'],['quine','carnap'],['On What There Is','Word and Object']),
    section('translation','Indeterminacy of translation',[
      'In Word and Object, Quine imagines radical translation: a linguist encountering a previously unknown language and trying to construct a translation manual from observable behavior and stimulation. His famous example involving a native utterance prompted by a rabbit is designed to show that multiple incompatible translation manuals can fit all behavioral evidence. The utterance might be translated as rabbit, undetached rabbit part, or a temporal stage of a rabbit, depending on broader analytical choices.',
      'The indeterminacy thesis challenges the idea that meanings are determinate entities waiting to be matched. Quine does not deny that translation works in ordinary life. He denies that there is always a further fact of the matter, beyond all possible evidence and theory, fixing one uniquely correct manual. This view unsettled philosophy of language because it attacks meanings not through skepticism about communication but through a naturalistic account of what evidence for meaning could be.'
    ],['philosophy-of-language','epistemology'],['quine'],['Word and Object']),
    section('reference','Inscrutability of reference and proxy functions',[
      'Quine\'s indeterminacy of translation is linked to the inscrutability of reference. Even within a theory, reference can be systematically reinterpreted by proxy functions while preserving the truth of whole sentences. What our words refer to is not fixed by a simple mental pointing relation. Reference depends on the overall structure of language, theory, and translation. This is one reason Quine distrusts meanings as intermediary entities between words and world.',
      'The thesis can sound more destabilizing than Quine intends. He is not saying ordinary talk about rabbits and tables is useless. He is saying that philosophical theories of reference should not posit hidden meanings to secure a determinate relation beyond all possible evidence. The cost is real: many philosophers think Quine makes language too behavioristic or too austere. The benefit is also real: he forces theories of meaning to explain what publicly accessible facts could make them true.'
    ],['philosophy-of-language','logic'],['quine'],['Word and Object','Ontological Relativity']),
    section('naturalized-epistemology','Naturalized epistemology',[
      'Quine\'s essay Epistemology Naturalized argues that traditional epistemology, understood as a project of justifying science from a firmer foundation, has failed. Instead of trying to derive the external world from sense data or meanings, we should study how sensory input leads to scientific theory as a chapter of psychology and natural science. Epistemology becomes continuous with empirical inquiry rather than a first philosophy standing above it.',
      'This proposal is radical and controversial. Supporters see it as honest: human knowledge is a natural phenomenon, and studying it scientifically is more fruitful than chasing impossible certainty. Critics worry that naturalized epistemology changes the subject, replacing normative questions about justification with descriptive questions about how beliefs are caused. Quine\'s challenge remains powerful because any non-naturalized epistemology must explain where its standards come from and how they relate to actual scientific practice.'
    ],['epistemology','philosophy-of-science','philosophy-of-mind'],['quine'],['Epistemology Naturalized']),
    section('logic-science','Logic, science, and revisability',[
      'Quine\'s holism implies that even logic is in principle revisable, though in practice it is among the most central and costly parts of our theory. This claim does not mean that contradictions are casually acceptable or that logic is a matter of taste. It means that no statement is immune solely because of its alleged meaning. If a revision of logic produced overwhelming theoretical gain, the web of belief model leaves conceptual space for it.',
      'This attitude distinguishes Quine from Carnap. Carnap could treat alternative logics as alternative linguistic frameworks chosen for practical reasons. Quine rejects a sharp distinction between choosing a language and making factual claims within it. For him, logic, mathematics, and science belong to one continuous theoretical enterprise. The price is a less tidy picture of convention; the gain is a more unified naturalism. Whether that gain is worth the price remains a central interpretive question.'
    ],['logic','philosophy-of-science','analytic-philosophy'],['quine','carnap'],['Two Dogmas of Empiricism','Philosophy of Logic']),
    section('carnap-relation','The dispute with Carnap revisited',[
      'Quine\'s relationship with Carnap is often narrated as a generational overthrow: Quine destroyed logical positivism and replaced it with naturalism. That story is too simple. Quine respected Carnap and shared many of his commitments, including logic, science, and suspicion of traditional metaphysics. Their disagreement concerned how to understand linguistic frameworks, analyticity, ontology, and the boundary between pragmatic choice and factual inquiry.',
      'Carnap wanted to treat some philosophical disputes as external questions about which language to adopt. Quine pressed that such choices are themselves continuous with our total theory and answerable to theoretical virtues. Carnap preserved a role for convention; Quine absorbed convention into the web of belief. The debate remains alive because both impulses are plausible. We do choose representational schemes for purposes, yet those choices are entangled with what we take the world to be like.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['quine','carnap'],['Two Dogmas of Empiricism','Empiricism, Semantics, and Ontology']),
    section('influence','Influence and post-analytic consequences',[
      'Quine influenced philosophy of language, metaphysics, epistemology, philosophy of science, and logic. His attack on analyticity shaped later debates about meaning and necessity. His criterion of ontological commitment affected metaphysics. His naturalism encouraged philosophers to take psychology, linguistics, and science seriously. Even those who reject his behaviorism or extensionalism often define their positions against his austere standard.',
      'The consequences were not all in one direction. Some philosophers used Quine to move toward naturalism and scientific realism. Others responded by defending analyticity, modality, propositions, or conceptual analysis in more sophisticated forms. Still others saw Quine as loosening the identity of analytic philosophy itself, because the old idea of philosophy as analysis of meanings became harder to maintain. Quine did not end analytic philosophy. He forced it to explain what analysis could be after the critique of meanings.'
    ],['analytic-philosophy','philosophy-of-language','philosophy-of-science'],['quine','carnap'],['Word and Object','Ontological Relativity']),
    section('misunderstandings','Common misunderstandings and live tensions',[
      'Quine is sometimes read as saying that there is no difference at all between central logical truths and ordinary empirical reports. That misses the practical structure of the web. Some beliefs are vastly more entrenched than others, and changing them would require massive theoretical compensation. He is also sometimes treated as a crude behaviorist who denies inner life. His real target is not experience but unexplained meanings and references posited beyond evidence.',
      'The tensions are serious. Can Quine account for normativity if epistemology becomes natural science? Can he explain communication without meanings? Is his extensionalism too restrictive for modality, intentionality, and ethics? Does his reliance on our best science smuggle in standards that naturalism cannot justify? These questions do not diminish his importance. They show why his work remains a turning point: after Quine, analytic philosophy had to become more self-conscious about its own methods.'
    ],['analytic-philosophy','epistemology','philosophy-of-language'],['quine'],['Word and Object','Epistemology Naturalized']),
    section('reading-strategy','How to read Quine',[
      'Start with Two Dogmas of Empiricism, but read it slowly and in connection with Carnap rather than as a free-standing slogan. Then read On What There Is for ontological commitment, selections from Word and Object for translation and reference, and Epistemology Naturalized for the shift in epistemology. From a Logical Point of View gives a useful collection of early essays, while Ontological Relativity shows the mature development of his themes.',
      'A good reading strategy is to track what Quine is refusing to posit. He often rejects meanings, propositions, analyticity, and first philosophy because he thinks they lack a clear place in our best account of inquiry. Ask whether the rejected item can be reconstructed in naturalistic terms, whether Quine has underestimated its role, or whether the demand for it was confused. Quine is demanding company, but he repays the effort by making the architecture of analytic philosophy visible.'
    ],['analytic-philosophy','logic','epistemology'],['quine','carnap'],['Two Dogmas of Empiricism','On What There Is','Word and Object','Epistemology Naturalized'])
  ],
  anscombe:[
    section('overview','Action, intention, and moral seriousness',[
      'G. E. M. Anscombe reshaped twentieth-century philosophy of action and helped redirect moral philosophy after the dominance of simple consequentialist and rule-centered frameworks. She was a student and translator of Wittgenstein, a Catholic philosopher with uncompromising moral convictions, and a writer whose compressed style can be difficult but exceptionally fertile. Her book Intention remains one of the central texts for understanding action, practical knowledge, and reasons.',
      'Anscombe matters because she made intention philosophically deep again. An intention is not merely an inner mental episode that causes bodily movement. It is connected with how an action is described, what question why receives as an answer, and how agents know what they are doing. In ethics, she argued that modern moral philosophy had lost the conceptual background that once made law-like obligation intelligible. Her work opened paths toward virtue ethics, action theory, and renewed attention to moral description.'
    ],['analytic-philosophy','ethics','philosophy-of-mind'],['anscombe','wittgenstein'],['Intention','Modern Moral Philosophy']),
    section('context','Wittgenstein, Oxford, and Catholic intellectual life',[
      'Anscombe\'s intellectual setting joined several worlds that are often kept apart. She studied at Oxford, became closely associated with Wittgenstein at Cambridge, translated and interpreted his later work, and wrote from within a serious Catholic moral outlook. She did not simply apply Wittgenstein\'s method to religious doctrine, nor did she turn analytic philosophy into theology. Her work shows how exact attention to language, action, and practice can coexist with firm moral and metaphysical commitments.',
      'The postwar context also matters. Analytic philosophy was increasingly attentive to ordinary language, mental concepts, and the grammar of action. Moral philosophy was wrestling with utilitarianism, emotivism, and the loss of older natural law frameworks. Anscombe entered these debates with unusual severity. She distrusted fashionable moral abstractions and asked how words such as intention, voluntary, must, and good actually function in human life. The result is philosophy at once linguistic, practical, and morally charged.'
    ],['analytic-philosophy','ethics','philosophy-of-language'],['anscombe','wittgenstein'],[]),
    section('wittgenstein','Anscombe as reader and transmitter of Wittgenstein',[
      'Anscombe was one of the most important mediators of Wittgenstein\'s philosophy. She translated Philosophical Investigations into English and wrote an influential introduction to the Tractatus. Her connection to Wittgenstein was personal, intellectual, and editorial. Yet she should not be treated only as a disciple. Her own work on intention, causality, and ethics develops independent lines of thought, even when Wittgensteinian attention to use, grammar, and practice is visible.',
      'Her reading of Wittgenstein helped shape English-language reception of both the early and later work. She understood that philosophical confusion often arises from forcing concepts into misleading pictures: mind as an inner object, meaning as a hidden accompaniment, action as mere movement plus mental cause. This sensitivity informs Intention. The book does not offer a psychological theory first and then examples. It examines the grammar of action descriptions and the circumstances in which questions of intention arise.'
    ],['analytic-philosophy','philosophy-of-language','philosophy-of-mind'],['anscombe','wittgenstein'],['Philosophical Investigations','An Introduction to Wittgenstein\'s Tractatus']),
    section('intention-book','Intention and the question why',[
      'Intention begins from a deceptively simple idea: intentional actions are those to which a certain sense of the question why applies. If someone is pumping water, poisoning inhabitants, moving an arm, or replenishing a water supply, the same bodily movement may fall under different descriptions. Asking why can elicit reasons that reveal what the agent is doing intentionally under some descriptions and not under others. Action cannot be understood by staring at movement alone.',
      'This approach changed philosophy of action. Anscombe does not identify intention with a private mental item hidden behind behavior. Nor does she reduce it to an external causal pattern. Intention belongs to the order of practical intelligibility: what the agent is up to, how the action is described, what reasons are operative, and how the action fits a plan. The theory is difficult because it asks readers to rethink the relation between mind and action rather than place intention in either one.'
    ],['philosophy-of-mind','analytic-philosophy'],['anscombe'],['Intention']),
    section('practical-knowledge','Practical knowledge',[
      'One of Anscombe\'s most influential claims is that intentional action involves practical knowledge. When an agent intentionally does something, she normally knows what she is doing without observing herself in the way an outsider must. A person writing a word does not infer from visual evidence that she is writing; her knowledge is connected with the action\'s being carried out. This is not infallibility, but it is a distinctive form of first-person knowledge.',
      'Practical knowledge reverses a familiar picture. We often think knowledge must be caused by the facts known. Anscombe suggests that in intentional action, knowledge can be the cause of what it understands: the order is practical rather than merely contemplative. This idea influenced later action theory, virtue ethics, and accounts of agency. It also raises hard questions. How does practical knowledge handle failure, accident, self-deception, or actions whose consequences exceed the agent\'s understanding?'
    ],['philosophy-of-mind','epistemology'],['anscombe'],['Intention']),
    section('description','Action under a description',[
      'Anscombe\'s insistence that actions are intentional under descriptions is one of her most durable insights. The same event can be described as moving a hand, operating a pump, filling a tank, or poisoning a household. An agent may intentionally do some of these things without intentionally doing others, depending on what she knows and why she acts. This undermines simple accounts that attach intention to bare physical movements.',
      'The point has ethical importance. Moral judgment often depends on how an action is described, but description is not a license for manipulation. Calling an act collateral damage, punishment, murder, treatment, or withdrawal of care can change the moral field. Anscombe\'s work asks philosophers to examine descriptions carefully, because intention, responsibility, and practical reasoning are embedded in them. Later debates about double effect, consequentialism, and action individuation all owe something to this insight.'
    ],['philosophy-of-mind','ethics','philosophy-of-language'],['anscombe'],['Intention']),
    section('modern-moral-philosophy','Modern Moral Philosophy and the critique of obligation',[
      'Anscombe\'s essay Modern Moral Philosophy made three famous interventions. She argued that moral philosophy should be set aside until we have an adequate philosophy of psychology; that concepts of moral obligation and moral duty survive from a law conception of ethics that many modern philosophers no longer accept; and that consequentialism, as she understood it, licenses grave moral errors by treating consequences as overriding prohibitions.',
      'The essay helped revive virtue ethics, though Anscombe herself did not simply offer a ready-made virtue theory. Her point was historical and conceptual: if one no longer believes in a divine lawgiver or comparable source of moral law, then retaining a special sense of moral ought may be confused. This diagnosis remains disputed. Secular Kantians, contractualists, and other moral philosophers deny that obligation requires the background she identifies. But her challenge forced moral philosophy to ask what its central concepts depend on.'
    ],['ethics','analytic-philosophy','philosophy-of-mind'],['anscombe'],['Modern Moral Philosophy']),
    section('consequentialism','Against consequentialism and moral calculation',[
      'Anscombe is one of the sharpest critics of consequentialism, a term she helped bring into philosophical prominence. Her objection is not simply that consequences do not matter. She objects to theories that permit any kind of action if the predicted outcome is sufficiently good. For Anscombe, some descriptions of action, such as intentionally killing the innocent, matter morally in a way that cannot be erased by adding up future benefits.',
      'This position connects her action theory with ethics. If intention and description are central to what an action is, then moral evaluation cannot ignore what the agent intentionally does as a means. Critics argue that absolute prohibitions can be rigid, or that consequences must sometimes dominate in tragic circumstances. Anscombe\'s reply is severe: a moral theory that makes anything available as a means has lost its grip on the reality of human action. The dispute remains live.'
    ],['ethics','analytic-philosophy'],['anscombe'],['Modern Moral Philosophy','Mr. Truman\'s Degree']),
    section('truman','Moral witness and public controversy',[
      'Anscombe\'s opposition to Oxford granting an honorary degree to Harry Truman made her moral philosophy publicly visible. She objected to Truman\'s responsibility for the atomic bombings of Hiroshima and Nagasaki, arguing that the intentional killing of civilians could not be justified by appeal to ending the war. Her pamphlet Mr. Truman\'s Degree shows her willingness to bring exact moral description into public judgment, even when the surrounding community preferred honorific consensus.',
      'This episode should be handled carefully. One can study Anscombe\'s argument without settling every historical question about wartime decision-making in a short profile. What matters philosophically is her refusal to let outcome language dissolve agency. She asks what was intentionally done, to whom, and under what description. Her public stance illustrates the same themes as Intention and Modern Moral Philosophy: moral reasoning depends on truthful description, not only on projected totals of harm and benefit.'
    ],['ethics'],['anscombe'],['Mr. Truman\'s Degree']),
    section('causality','Causality, determination, and the shape of explanation',[
      'Anscombe also wrote influentially on causality. In Causality and Determination, she challenged the assumption that causation must be understood as exceptionless law-like necessitation. Ordinary causal concepts, she argued, are more varied. We recognize causing, preventing, enabling, sustaining, and interfering without always knowing universal laws. This view resisted both Humean simplifications and overly rigid scientific images of causation.',
      'Her account matters for action and mind as well as metaphysics. If causation is not always a matter of strict deterministic law, then explaining action by reasons need not be forced into a crude model of inner events producing bodily movements by psychological mechanism. Anscombe did not deny science or causal explanation. She objected to philosophical pictures that make causation narrower than our actual practices of explanation. Later work on powers, agency, and causal pluralism often echoes this challenge.'
    ],['philosophy-of-science','philosophy-of-mind','analytic-philosophy'],['anscombe'],['Causality and Determination']),
    section('influence','Influence on action theory and virtue ethics',[
      'Anscombe\'s influence on philosophy of action is difficult to overstate. Donald Davidson, Michael Thompson, Jennifer Hornsby, John McDowell, Elizabeth Anscombe\'s own students and critics, and many others developed or contested ideas about reasons, causes, descriptions, and practical knowledge. Even philosophers who reject her conclusions often begin from questions she made unavoidable. What is an intentional action? How are reasons related to causes? What does an agent know without observation?',
      'In ethics, Modern Moral Philosophy helped open space for the revival of virtue ethics associated with figures such as Philippa Foot, Alasdair MacIntyre, and Rosalind Hursthouse, though each developed the project differently. Anscombe\'s challenge to modern obligation language and consequentialism encouraged renewed attention to character, practical reason, human life, and moral psychology. Her influence is therefore not a school with one doctrine, but a set of redirected questions about agency and the moral life.'
    ],['ethics','philosophy-of-mind','analytic-philosophy'],['anscombe','wittgenstein'],['Intention','Modern Moral Philosophy']),
    section('misunderstandings','Common misunderstandings and interpretive difficulties',[
      'Anscombe is sometimes caricatured as merely a religious moralist importing Catholic doctrine into analytic philosophy. That misses the philosophical originality of her work on intention, action description, and practical knowledge. It is equally mistaken to detach her technical work entirely from her moral seriousness. Her Catholic commitments and her analytic methods interact, but not as a simple substitution of authority for argument. She uses philosophical analysis to show what moral description requires.',
      'Her writing can also mislead by compression. Intention is short, but it is not introductory. Arguments appear through examples, distinctions, and grammatical reminders rather than through textbook signposting. Readers may think she is making behaviorist claims because she resists inner mental objects, or anti-causal claims because she criticizes certain causal pictures. Usually the truth is subtler. She is trying to change the picture of action so that mind, reason, and embodiment are not pulled apart.'
    ],['analytic-philosophy','ethics','philosophy-of-mind'],['anscombe','wittgenstein'],['Intention','Modern Moral Philosophy']),
    section('reading-strategy','How to read Anscombe',[
      'Begin with Modern Moral Philosophy to see the force of her ethical challenge, but do not stop there. Read Intention slowly, with attention to examples and to the question why. It helps to write out different descriptions of the same action and ask which are intentional, known, accidental, or merely consequential. Then read Causality and Determination and selected essays on ethics to see how her action theory connects with moral and metaphysical concerns.',
      'Read Anscombe beside Wittgenstein, but let her remain herself. Wittgenstein helps explain her attention to grammar and practice; Aquinas and Catholic moral thought help explain parts of her ethical background; later action theory shows how fertile her questions became. The guiding habit should be descriptive honesty. Before applying a moral theory or a philosophy of mind, ask what the agent is doing, how it is known, under what description it is chosen, and why that description matters.'
    ],['analytic-philosophy','ethics','philosophy-of-mind'],['anscombe','wittgenstein'],['Modern Moral Philosophy','Intention','Causality and Determination'])
  ]
};
